base_css:
/* Base Resets */
    body {
      margin: 0;
      font-family: 'DM Sans', -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
      background-color: var(--bg-body);
      color: var(--text);
      overflow-x: hidden;
      padding-top: var(--header-h); 
    }
    @media (max-width: 991px) { body { padding-top: 64px; } }

    a { text-decoration: none; color: var(--primary); transition: color var(--t); }
    a:hover { color: var(--primary-2); }
    p { line-height: 1.7; color: var(--text-s); font-size: 0.95rem; }

    .font-syne { font-family: 'Syne', sans-serif; }

    /* ========================================================================== */
    /* COMPONENTS & TYPOGRAPHY                                                    */
    /* ========================================================================== */
    .section-title {
      position: relative; padding-bottom: .75rem; margin-bottom: 2rem;
      font-weight: 800; color: var(--primary-d); font-family: 'Syne', sans-serif;
      font-size: clamp(1.6rem, 4vw, 2.2rem);
    }
    .section-title::after {
      content: ''; position: absolute; bottom: 0; left: 0;
      width: 60px; height: 4px; border-radius: 2px;
      background: linear-gradient(90deg, var(--primary), var(--gold));
    }
    .section-title.center::after { left: 50%; transform: translateX(-50%); }

    .hover-lift { transition: transform 0.3s var(--ease), box-shadow 0.3s var(--ease), border-color 0.3s; }
    .hover-lift:hover { transform: translateY(-6px); box-shadow: var(--sh-md); border-color: rgba(51,133,255,0.15); z-index: 2; }

    /* ========================================================================== */
    /* HERO SECTION                                                               */
    /* ========================================================================== */
    .hero-banner {
      position: relative; overflow: hidden;
      background: linear-gradient(135deg, var(--digital-blue-950) 0%, var(--digital-blue-900) 50%, var(--digital-blue-800) 100%);
      padding: 80px 0 100px; text-align: center;
    }
    .hero-banner::before {
      content: ''; position: absolute; inset: 0;
      background-image: 
        radial-gradient(circle at 15% 50%, rgba(51, 133, 255, 0.2), transparent 30%),
        radial-gradient(circle at 85% 30%, rgba(51, 133, 255, 0.2), transparent 30%);
      z-index: 1; pointer-events: none;
    }
    .hero-ring {
      position: absolute; border-radius: 50%; border: 1px solid rgba(255,255,255,.05);
      pointer-events: none; z-index: 1;
    }
    .hero-ring-1 { width: 600px; height: 600px; top: -200px; left: -150px; border-color: rgba(51, 133, 255, 0.15); }
    .hero-ring-2 { width: 400px; height: 400px; bottom: -100px; right: -50px; border-color: rgba(255,255,255,.05); }

    .hero-content { position: relative; z-index: 3; max-width: 800px; margin: 0 auto; }
    .hero-breadcrumb {
      display: inline-flex; align-items: center; gap: 8px;
      color: var(--gold); font-size: .75rem; font-weight: 800; text-transform: uppercase; letter-spacing: 0.08em;
      background: rgba(51, 133, 255, 0.15); border: 1px solid rgba(51, 133, 255, 0.3);
      border-radius: 50px; padding: 6px 16px; margin-bottom: 24px;
      transition: all var(--t);
    }
    .hero-breadcrumb:hover { background: rgba(51, 133, 255, 0.25); color: #fff; transform: translateY(-2px); }
    .hero-banner h1 {
      font-size: clamp(2.5rem, 5vw, 3.8rem); font-weight: 800; color: #fff; 
      letter-spacing: -.02em; margin-bottom: 16px; text-shadow: 0 4px 20px rgba(0,0,0,0.3);
    }
    .hero-banner p {
      font-size: 1.15rem; color: rgba(255,255,255,.75); line-height: 1.7; margin-bottom: 0;
    }

    /* ========================================================================== */
    /* CONTENT BLOCKS                                                             */
    /* ========================================================================== */
    .content-card {
      background: #fff;
      border: 1px solid var(--bdr);
      border-radius: var(--r-xl);
      padding: 40px;
      box-shadow: var(--sh-sm);
      margin-top: -40px; /* Overlap hero slightly */
      position: relative;
      z-index: 10;
    }
    @media (max-width: 768px) {
      .content-card { padding: 24px; margin-top: -30px; }
    }

    /* ========================================================================== */
    /* GOVERNANCE CARDS                                                           */
    /* ========================================================================== */
    .gov-grid {
      display: grid;
      grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));
      gap: 24px;
      margin-top: 40px;
    }
    .gov-card {
      background: #fff;
      border: 1px solid var(--bdr);
      border-radius: var(--r-md);
      padding: 32px 24px;
      cursor: pointer;
      display: flex;
      flex-direction: column;
      height: 100%;
    }
    .gov-icon-wrap {
      width: 64px; height: 64px; border-radius: 16px;
      background: var(--digital-blue-50);
      display: flex; align-items: center; justify-content: center;
      font-size: 2rem; margin-bottom: 20px;
      border: 1px solid rgba(51,133,255,0.1);
      transition: all var(--t);
    }
    .gov-card:hover .gov-icon-wrap {
      background: var(--primary); transform: scale(1.05) rotate(-5deg);
    }
    .gov-card:hover .gov-icon-wrap i { color: #fff; } /* If using bootstrap icon */

    .gov-title {
      font-size: 1.25rem; font-weight: 800; color: var(--primary-d);
      margin-bottom: 10px; font-family: 'Syne', sans-serif;
    }
    .gov-desc-preview {
      font-size: 0.9rem; color: var(--text-s); line-height: 1.6; margin-bottom: 20px;
      display: -webkit-box; -webkit-line-clamp: 3; -webkit-box-orient: vertical; overflow: hidden;
    }
    .gov-action {
      margin-top: auto; font-size: 0.85rem; font-weight: 700; color: var(--primary);
      display: inline-flex; align-items: center; gap: 6px;
      transition: gap var(--t);
    }
    .gov-card:hover .gov-action { gap: 10px; color: var(--primary-2); }

    /* ========================================================================== */
    /* BOOTSTRAP MODAL OVERRIDES (Digital Blue SaaS)                              */
    /* ========================================================================== */
    .gov-modal-content { 
      border-radius: 24px; overflow: hidden; border: none; 
      box-shadow: var(--sh-lg); background: #fff;
    }
    .gov-modal-header {
      background: var(--primary-l);
      padding: 32px 40px;
      border-bottom: 1px solid var(--bdr-s);
      position: relative;
    }
    .gov-modal-title { 
      color: var(--primary-d); font-weight: 800; font-size: 1.6rem; margin: 0; 
      font-family: 'Syne', sans-serif; line-height: 1.2;
    }
    .modal-emoji { font-size: 2.8rem; line-height: 1; margin-right: 16px; }

    .btn-close-custom {
      position: absolute; top: 24px; right: 24px;
      width: 36px; height: 36px; border-radius: 50%;
      background: var(--sur); border: 1px solid var(--bdr);
      display: flex; align-items: center; justify-content: center;
      color: var(--text-m); font-size: 1.2rem; cursor: pointer;
      transition: all var(--t);
    }
    .btn-close-custom:hover { background: var(--error); color: #fff; border-color: var(--error); transform: rotate(90deg); }

    .gov-modal-body { padding: 40px; }
    .modal-desc { font-size: 1rem; color: var(--text-s); line-height: 1.7; margin-bottom: 32px; }

    .modal-detail-row { 
      display: flex; align-items: flex-start; gap: 16px; 
      padding: 16px 0; border-bottom: 1px solid var(--bdr-s); 
    }
    .modal-detail-row:last-child { border-bottom: none; padding-bottom: 0; }
    .modal-di { 
      width: 48px; height: 48px; border-radius: 12px; 
      background: var(--digital-blue-50); color: var(--digital-blue-600);
      display: flex; align-items: center; justify-content: center; flex-shrink: 0;
      border: 1px solid rgba(0,102,255,0.05); font-size: 1.2rem;
    }
    .modal-dl { 
      font-size: 0.72rem; color: var(--text-m); font-weight: 800; 
      text-transform: uppercase; letter-spacing: 0.08em; margin-bottom: 4px; 
    }
    .modal-dv { font-size: 1rem; color: var(--primary-d); font-weight: 700; line-height: 1.5; }

    @media (max-width: 768px) {
      .gov-modal-header { padding: 24px; flex-direction: column; align-items: flex-start !important; }
      .modal-emoji { margin-bottom: 12px; }
      .gov-modal-body { padding: 24px; }
    }

    /* ========================================================================== */
    /* ANIMATIONS (Scroll Reveal)                                                 */
    /* ========================================================================== */
    .fade-up { opacity: 0; transform: translateY(32px); transition: opacity .6s var(--ease), transform .6s var(--ease); }
    .fade-up.visible { opacity: 1; transform: translateY(0); }
    .fade-in { opacity: 0; transition: opacity .6s var(--ease); }
    .fade-in.visible { opacity: 1; }

    .delay-1 { transition-delay: .05s; }
    .delay-2 { transition-delay: .1s; }
    .delay-3 { transition-delay: .15s; }
    .delay-4 { transition-delay: .2s; }

base_js:
/* ========================================================================== */
  /* PAGE INTERACTIONS (Scroll Reveal & Modals)                                 */
  /* ========================================================================== */
  (function () {
    'use strict';

    /* ── Scroll-Reveal (IntersectionObserver) ── */
    const revealEls = document.querySelectorAll('.fade-up, .fade-in');
    if (revealEls.length) {
      const obs = new IntersectionObserver(
        (entries) => {
          entries.forEach((entry) => {
            if (entry.isIntersecting) {
              entry.target.classList.add('visible');
              obs.unobserve(entry.target);
            }
          });
        },
        { threshold: 0.15 }
      );
      revealEls.forEach((el) => obs.observe(el));
    }

    /* ── Bootstrap Modal — Gov Card click handler ── */
    const govModalEl = document.getElementById('govModal');
    let bsModal = null;

    if (govModalEl && typeof bootstrap !== 'undefined') {
      bsModal = new bootstrap.Modal(govModalEl);
    }

    document.querySelectorAll('.gov-card').forEach((card) => {
      card.addEventListener('click', () => {
        document.getElementById('mEmoji').textContent   = card.dataset.emoji   || '';
        document.getElementById('mGTitle').textContent  = card.dataset.title   || '';
        document.getElementById('mGDesc').textContent   = card.dataset.desc    || '';
        document.getElementById('mGRole').textContent   = card.dataset.role    || '';
        document.getElementById('mGMandate').textContent= card.dataset.mandate || '';
        document.getElementById('mGWeb').textContent    = card.dataset.website || '';
        document.getElementById('mGImpact').textContent = card.dataset.impact  || '';

        if (bsModal) {
          bsModal.show();
        }
      });
    });

  })();
